import{_ as r,o as t,c as a,ae as i}from"./chunks/framework.Bc_rTVfd.js";const u=JSON.parse('{"title":"3-Order Filtration: Signal Engine","description":"","frontmatter":{},"headers":[],"relativePath":"strategy/3order-filter.md","filePath":"strategy/3order-filter.md"}'),l={name:"strategy/3order-filter.md"};function n(o,e,s,d,g,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_3-order-filtration-signal-engine" tabindex="-1">3-Order Filtration: Signal Engine <a class="header-anchor" href="#_3-order-filtration-signal-engine" aria-label="Permalink to &quot;3-Order Filtration: Signal Engine&quot;">​</a></h1><p><strong>&quot;시장의 소음(Noise)은 필연적입니다. 우리는 그 소음을 제거하는 것이 아니라, 유의미한 &#39;신호의 진입(Signal Penetration)&#39;을 측정합니다.&quot;</strong> - WeJump Labs</p><hr><h2 id="🏗️-1-필터-아키텍처-개요" tabindex="-1">🏗️ 1. 필터 아키텍처 개요 <a class="header-anchor" href="#🏗️-1-필터-아키텍처-개요" aria-label="Permalink to &quot;🏗️ 1. 필터 아키텍처 개요&quot;">​</a></h2><p>CBVR v2.3의 엔진은 **Level(공간), Speed(시간/강도), Trend(방향)**라는 세 가지 독립적인 레이어를 통해 시장을 스캔합니다.</p><p><img src="https://crowmag2.github.io/wejump/CBVR%EB%A1%9C%EC%A7%81%EC%84%A4%EB%AA%85.jpg" alt="CBVR Logic"></p><h3 id="📊-layer-1-level-filter-공간-분석" tabindex="-1">📊 Layer 1: Level Filter (공간 분석) <a class="header-anchor" href="#📊-layer-1-level-filter-공간-분석" aria-label="Permalink to &quot;📊 Layer 1: Level Filter (공간 분석)&quot;">​</a></h3><ul><li><strong>메커니즘:</strong> EMA 기반의 다층 Envelope 채널 (±N%, ±2N%, ±4N%)을 활용합니다.</li><li><strong>역할:</strong> 현재 가격이 장기 평균으로부터 어느 정도 이격되어 있는지, &#39;평균회귀(Mean Reversion)&#39;의 임계점에 도달했는지를 판별하여 기본 비중을 설정합니다.</li></ul><h3 id="⚡-layer-2-speed-filter-강도-분석" tabindex="-1">⚡ Layer 2: Speed Filter (강도 분석) <a class="header-anchor" href="#⚡-layer-2-speed-filter-강도-분석" aria-label="Permalink to &quot;⚡ Layer 2: Speed Filter (강도 분석)&quot;">​</a></h3><ul><li><strong>메커니즘:</strong> ATR 기반의 동적 변동성 트리거를 적용합니다. (임계치 ±6% 이상 시 발동)</li><li><strong>역할:</strong> 의미 없는 미세 조정(Churning)을 방지하고, **&#39;유의미한 충격&#39;**이 발생했을 때만 기계적으로 리밸런싱을 트리거합니다.</li><li><strong>이점:</strong> 정기 리밸런싱 대비 거래 비용을 70% 이상 절감하는 &#39;이벤트 기반(Event-driven)&#39; 실행이 핵심입니다.</li></ul><h3 id="📐-layer-3-trend-filter-벡터-분석" tabindex="-1">📐 Layer 3: Trend Filter (벡터 분석) <a class="header-anchor" href="#📐-layer-3-trend-filter-벡터-분석" aria-label="Permalink to &quot;📐 Layer 3: Trend Filter (벡터 분석)&quot;">​</a></h3><ul><li><strong>메커니즘:</strong> halfMA(변수명) 기울기 및 벡터 편차 분석을 통한 추세 강도 수치화.</li><li><strong>역할:</strong> 현재의 이격이 단순 일시적 과매수/과매도인지, 아니면 강력한 **&#39;레짐 체인지(Regime Change)&#39;**인지를 벡터로 검증하여 비중을 강화하거나 헤징을 예고합니다.</li></ul><hr><h2 id="🛡️-2-eavs-efficiency-adjusted-volatility-scaling" tabindex="-1">🛡️ 2. EAVS (Efficiency-Adjusted Volatility Scaling) <a class="header-anchor" href="#🛡️-2-eavs-efficiency-adjusted-volatility-scaling" aria-label="Permalink to &quot;🛡️ 2. EAVS (Efficiency-Adjusted Volatility Scaling)&quot;">​</a></h2><p>CBVR의 정수는 Kaufman의 효율성 지수(ER)를 아키텍처에 내재화한 것입니다.</p><ul><li><strong>Chop Zone (횡보장):</strong> EAVS 모듈이 작동하여 비중을 극단적으로 축소하고 휩소(Whipsaw) 공세를 견뎌냅니다.</li><li><strong>Trend Zone (추세장):</strong> 벡터의 순응도에 따라 레버리지를 확장하여 구조적 이익을 극대화합니다.</li></ul><hr><blockquote><p><strong>Key Insight:</strong> &quot;우리는 가격을 맞추는 도박사가 아닙니다. **시장의 물리적 관성(Momentum)과 탄성(Mean Reversion)**을 동시 측정하는 정밀한 엔지니어입니다.&quot; 🐯🐾</p></blockquote>',18)])])}const f=r(l,[["render",n]]);export{u as __pageData,f as default};
